#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__attribute__((reqd_work_group_size(1, 1, 1)))
void dynproc_kernel(
    int arg0,
    const __global int* d_gpuWall,
    const __global int* src_buf,
    __global int* dst_buf,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* d_outputBuffer
)
{
    int n = 0; // Single thread handles all columns sequentially per step due to reqd_work_group_size(1,1,1) and algorithm dependency

    int current_t = t;
    int steps_to_run = arg0;

    // We need to iterate 'steps_to_run' times, swapping src/dst buffers logically
    // Since we cannot swap global pointers easily in a loop without extra args, 
    // we use the logical swap pattern from the host or perform iterations internally.
    // However, the host launches this kernel multiple times for each pyramid_height chunk.
    // Inside one launch, we perform 'arg0' steps.

    // The host passes src_buf and dst_buf for the current swap state.
    // But wait, the OpenMP code does:
    // temp = src; src = dst; dst = temp;
    // Then computes dst using src.
    // So in each step, the 'src' is the previous 'dst', and 'dst' becomes the new result.

    // Since the kernel is launched in a loop by the host with swapped buffers,
    // this kernel only needs to perform ONE step of the recurrence?
    // Let's re-read the host code:
    // for (int t = 0; t < rows - 1; t += pyramid_height) {
    //   swap(src, dst);
    //   set args...
    //   launch
    // }
    // The host loop increments t by pyramid_height.
    // The kernel argument 'arg0' is MIN(pyramid_height, rows-t-1).
    // This implies the kernel is expected to run 'arg0' steps internally?
    // OR the host launches the kernel 'pyramid_height' times?
    // Looking at the host code: "cl.launch(kn);" is called once per outer loop iteration.
    // Therefore, the kernel MUST perform 'arg0' iterations internally.

    // But how to handle the buffer swapping inside the kernel?
    // The host passes d_gpuResult[src] and d_gpuResult[final_ret].
    // If the kernel runs multiple steps, it needs to swap these pointers logically inside.

    int step_count = arg0;

    // We need a temporary buffer for swapping if we do multiple steps inside?
    // No, the host manages two buffers (0 and 1).
    // If step_count > 1, we need to alternate between the two passed buffers?
    // Actually, if the host swaps the pointers passed to src and dst for the next launch,
    // then for a single launch with step_count > 1, we must simulate the swapping internally.

    // Let's assume the passed src_buf is the input for step 0, and dst_buf is the output for step 0.
    // For step 1, the input should be the output of step 0 (dst_buf), and the output should be src_buf (reused).

    const __global int* current_src = src_buf;
    __global int* current_dst = dst_buf;

    for (int step = 0; step < step_count; step++) {
        // Process all columns for this step
        // Since work group size is 1, we loop over cols
        for (n = 0; n < cols; n++) {
            int min_val = current_src[n];

            if (n > 0) {
                int left = current_src[n - 1];
                if (left < min_val) min_val = left;
            }

            if (n < cols - 1) {
                int right = current_src[n + 1];
                if (right < min_val) min_val = right;
            }

            // wall index: wall[t + 1 + step][n]
            // The host passes d_gpuWall which is (data + cols), i.e., starting from row 1.
            // Original row index in wall: t + 1 + step
            // Index in d_gpuWall: (t + 1 + step - 1) * cols + n = (t + step) * cols + n
            int wall_val = d_gpuWall[(t + step) * cols + n];

            current_dst[n] = wall_val + min_val;
        }

        // Swap pointers for next iteration if needed
        if (step < step_count - 1) {
            const __global int* temp_ptr = current_src;
            current_src = current_dst;
            current_dst = (__global int*)temp_ptr;
        }
    }

    // Optional: Write something to outputBuffer to indicate completion or debug, 
    // though the original OpenMP code doesn't explicitly write to a separate output buffer aside from result.
    // The infrastructure code reads d_outputBuffer but the OpenMP code doesn't write to it.
    // We'll leave it untouched or write a marker if required by infrastructure, 
    // but the prompt says "Preserve the algorithm...". The OpenMP code doesn't write to it.
    // The infrastructure expects it though. Let's write a simple marker.
    if (get_global_id(0) == 0) {
        d_outputBuffer[0] = 1; 
    }
}
